export function FormDataHas(self: bigint, name: string): boolean {
  const obj = lookupFormData(self);
  return obj.has(name);
}

/**
 * `set()` operation.
 */
export function FormDataSet(self: bigint, name: string, value: string): void {
  const obj = lookupFormData(self);
  obj.set(name, value);
}

